 1	import * as React from "react";
 2	import {
 3	  FormGroup,
 4	  FormHelperText,
 5	  HelperText,
 6	  HelperTextItem,
 7	  NumberInput,
 8	} from "@patternfly/react-core";
 9	import { useField } from "formik";
10	import toInteger from "lodash-es/toInteger";
11	import { FieldProps } from "../../copiedFromConsole/formik-fields/field-types";
12	import { ExclamationCircleIcon } from "@patternfly/react-icons";
13	
14	type NumberSpinnerFieldProps = FieldProps & {
15	  min?: number;
16	  max?: number;
17	  onChange?: () => void;
18	  onBlur?: () => void;
19	};
20	
21	const NumberSpinnerField: React.FC<NumberSpinnerFieldProps> = ({
22	  label,
23	  labelIcon,
24	  helpText,
25	  required,
26	  onChange,
27	  onBlur,
28	  ...props
29	}) => {
30	  const [field, { touched, error }, { setValue, setTouched }] = useField<
31	    number | ""
32	  >(props.name);
33	
34	  const isValid = !(touched && error);
35	  const errorMessage = !isValid ? error : "";
36	
37	  const changeValueBy = (operation: number) => {
38	    const newValue = toInteger(field.value) + operation;
39	    setValue(newValue);
40	    setTouched(true);
41	    if (onChange) {
42	      onChange();
43	    }
44	    if (onBlur) {
45	      onBlur();
46	    }
47	  };
48	
49	  const validated = isValid ? "default" : "error";
50	
51	  return (
52	    <FormGroup
53	      fieldId={props.name}
54	      label={label}
55	      isRequired={required}
56	      labelHelp={labelHelp}
57	    >
58	      <NumberInput
59	        name={props.name}
60	        id={props.name}
61	        value={field.value}
62	        onMinus={() => changeValueBy(-1)}
63	        onPlus={() => changeValueBy(1)}
64	        onChange={(event) => {
65	          const target = event.target as HTMLInputElement;
66	          setValue(target.value === "" ? target.value : +target.value);
67	          if (onChange) {
68	            onChange();
69	          }
70	        }}
71	        onBlur={(event) => {
72	          field.onBlur(event);
73	          if (onBlur) {
74	            onBlur();
75	          }
76	        }}
77	        minusBtnAriaLabel="Decrement"
78	        plusBtnAriaLabel="Increment"
79	      />
80	      <FormHelperText>
81	        <HelperText>
82	          <HelperTextItem
83	            variant={validated}
84	            {...(validated === "error" && { icon: <ExclamationCircleIcon /> })}
85	          >
86	            {errorMessage || helpText}
87	          </HelperTextItem>
88	        </HelperText>
89	      </FormHelperText>
90	    </FormGroup>
91	  );
92	};
93	
94	export default NumberSpinnerField;

